1195→                // make a copy of threads to avoid holding lock
1196→                for (final StreamThread streamThread : new ArrayList<>(threads)) {
1197→                    final boolean callingThreadIsNotCurrentStreamThread = !streamThread.getName().equals(Thread.currentThread().getName());
1198→                    if (streamThread.isThreadAlive() && (callingThreadIsNotCurrentStreamThread || numLiveStreamThreads() == 1)) {
1199→                        log.info("Removing StreamThread {}", streamThread.getName());
1200→                        streamThread.shutdown(org.apache.kafka.streams.CloseOptions.GroupMembershipOperation.LEAVE_GROUP);
1201→                        if (callingThreadIsNotCurrentStreamThread) {
1202→                            final long remainingTimeMs = timeoutMs - (time.milliseconds() - startMs);
1203→                            if (remainingTimeMs <= 0 || !streamThread.waitOnThreadState(StreamThread.State.DEAD, remainingTimeMs)) {
1204→                                log.warn("{} did not shutdown in the allotted time.", streamThread.getName());
1205→                                // Don't remove from threads until shutdown is complete. We will trim it from the
1206→                                // list once it reaches DEAD, and if for some reason it's hanging indefinitely in the
1207→                                // shutdown then we should just consider this thread.id to be burned
1208→                            } else {
1209→                                log.info("Successfully removed {} in {}ms", streamThread.getName(), time.milliseconds() - startMs);
1210→                                threads.remove(streamThread);
1211→                                queryableStoreProvider.removeStoreProviderForThread(streamThread.getName());
1212→                            }
1213→                        } else {
1214→                            log.info("{} is the last remaining thread and must remove itself, therefore we cannot wait "
1215→                                + "for it to complete shutdown as this will result in deadlock.", streamThread.getName());
1216→                        }
1217→
1218→                        final long cacheSizePerThread = cacheSizePerThread(numLiveStreamThreads());
1219→                        log.info("Resizing thread cache due to thread removal, new cache size per thread is {}", cacheSizePerThread);
1220→                        resizeThreadCache(cacheSizePerThread);
1221→                        final long remainingTimeMs = timeoutMs - (time.milliseconds() - startMs);
1222→                        if (remainingTimeMs <= 0) {
1223→                            throw new TimeoutException("Thread " + streamThread.getName() + " did not stop in the allotted time");
1224→                        }
1225→                        return Optional.of(streamThread.getName());
